Write-Host "Ajout BudgetFormPage" -ForegroundColor Cyan
function Write-B64 { param($p,$b)
  $full = Join-Path (Get-Location).Path $p
  $dir = Split-Path $full -Parent
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [Convert]::FromBase64String($b)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($full, $text, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  -> $p" -ForegroundColor Gray
}
Write-B64 "frontend\src\ui\pages\BudgetFormPage.tsx" ""


# Patch App.tsx to add BudgetFormPage route
$app = Get-Content "frontend\src\ui\App.tsx" -Raw
if (-not $app.Contains("BudgetFormPage")) {
  $app = $app -replace 'import \{ ComparePage \}', 'import { BudgetFormPage } from "./pages/BudgetFormPage";`nimport { ComparePage }'
  $app = $app -replace '<Route path="/compare"', '<Route path="/saisie" element={<BudgetFormPage />} />`n          <Route path="/compare"'
  [System.IO.File]::WriteAllText((Join-Path (Get-Location).Path "frontend\src\ui\App.tsx"), $app, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  App.tsx patched" -ForegroundColor Gray
}


# Patch Layout.tsx to add nav item
$layout = Get-Content "frontend\src\ui\Layout.tsx" -Raw
if (-not $layout.Contains("saisie")) {
  $layout = $layout -replace '{to:"/users"', '{to:"/saisie", label:"Saisie et Formulaires", tag:"NEW"},{to:"/users"'
  [System.IO.File]::WriteAllText((Join-Path (Get-Location).Path "frontend\src\ui\Layout.tsx"), $layout, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  Layout.tsx patched" -ForegroundColor Gray
}

git add -A
$c = git commit -m "feat: module saisie budgetaire — formulaires plan, lignes, engagements" 2>&1
Write-Host "  $c" -ForegroundColor Gray
$p = git push origin main 2>&1
Write-Host "  $p" -ForegroundColor Gray
Write-Host "TERMINE ! Nouvelle page : /saisie" -ForegroundColor Green